// Build URL and response based on what needs processing
const row = $input.first().json;

if (!row || !row.cc_id) {
  return { message: 'No CC to process' };
}

const ccId = row.cc_id;
const entryDone = row.entries_runned === 1;
const outputDone = row.outputs_runned === 1;

// Determina qual tipo processar
let type = 'entrada';
let urlType = 'Entrada';

if (entryDone && !outputDone) {
  type = 'saida';
  urlType = 'Saida';
}

// Gera URL do VHSYS
const today = new Date();
const dd = String(today.getDate()).padStart(2, '0');
const mm = String(today.getMonth() + 1).padStart(2, '0');
const yyyy = today.getFullYear();
const dateStr = `${dd}/${mm}/${yyyy}`;

const vhsysUrl = `https://app.vhsys.com.br/Relatorio/Relatorio.CentroCustos.JSON.php?considerarData=pagamento&Data1=01/01/2002&Data2=${dateStr}&ListarCentroAtivoSemLancamento=1&modelo=2&Nome=&Cod=&Tipo=${urlType}&Centro=${ccId}&Categoria=null&buscar=1`;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_next_url',
  event: 'next_url_generated',
  cc_id: ccId,
  type: type,
  level: 'info'
}));

// IMPORTANTE: TypeScript espera data.url.url (estrutura aninhada)
// Linha 64 do updateReportCC.ts faz: const { url: dataUrl } = data
// Linha 71 faz: await getData(dataUrl.url)
return {
  url: {
    url: vhsysUrl,
    cc_id: ccId,
    type: type
  }
};
